# @cctt_verify {"v":2,"sym":"sympy.printing.tests.test_mathml.test_print_hadamard","kind":"function","src_hash":"8b762bdfc034d16b","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"test_print_hadamard()","rhs":"test_print_hadamard produces the expected output","over":{"base":"Any"},"name":"test_print_hadamard_correct"},"guarantee":"test_print_hadamard produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.printing.tests.test_mathml.test_print_hadamard_correct","statement":"Path(test_print_hadamard(x), test_print_hadamard produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"2c1c046aabbc94a5"}
def test_print_hadamard():
    from sympy.matrices.expressions import HadamardProduct
    from sympy.matrices.expressions import Transpose

    X = MatrixSymbol('X', 2, 2)
    Y = MatrixSymbol('Y', 2, 2)

    assert mathml(HadamardProduct(X, Y*Y), printer="presentation") == \
        '<mrow>' \
        '<mi>X</mi>' \
        '<mo>&#x2218;</mo>' \
        '<msup><mi>Y</mi><mn>2</mn></msup>' \
        '</mrow>'

    assert mathml(HadamardProduct(X, Y)*Y, printer="presentation") == \
        '<mrow>' \
        '<mrow><mo>(</mo>' \
        '<mrow><mi>X</mi><mo>&#x2218;</mo><mi>Y</mi></mrow>' \
        '<mo>)</mo></mrow>' \
        '<mo>&InvisibleTimes;</mo><mi>Y</mi>' \
        '</mrow>'

    assert mathml(HadamardProduct(X, Y, Y), printer="presentation") == \
        '<mrow>' \
        '<mi>X</mi><mo>&#x2218;</mo>' \
        '<mi>Y</mi><mo>&#x2218;</mo>' \
        '<mi>Y</mi>' \
        '</mrow>'

    assert mathml(
        Transpose(HadamardProduct(X, Y)), printer="presentation") == \
            '<msup>' \
            '<mrow><mo>(</mo>' \
            '<mrow><mi>X</mi><mo>&#x2218;</mo><mi>Y</mi></mrow>' \
            '<mo>)</mo></mrow>' \
            '<mo>T</mo>' \
            '</msup>'


